    return calEvent.customReplyToEmail;
  }

  if (excludeOrganizerEmail) {
    return null;
  }

  return calEvent.organizer.email;
};

export function convertErrorWithCodeToTRPCError(cause: unknown) {
  if (cause instanceof ErrorWithCode) {
    const statusCode = getHttpStatusCode(cause);
    return new TRPCError({
      code: httpStatusToTrpcCode(statusCode),
      message: cause.message ?? "",
      cause: cause,
    });
  }

  return cause;
}

#clean(): Record<string, Cookie> {
  const cleanedChunks: Record<string, Cookie> = {}
  for (const name in this.#chunks) {
    delete this.#chunks?.[name]
    cleanedChunks[name] = {
      name,
      value: "",
      options: { ...this.#option.options, maxAge: 0 },
    }
  }
  return cleanedChunks
}

