export function loadConfigFile(): CliConfigFile {
  const configPath = getConfigPath();
  if (!fs.existsSync(configPath)) {
    return {};
  }

  const parsed = JSON.parse(fs.readFileSync(configPath, "utf-8")) as unknown;
  return zCliConfigFileSchema.parse(parsed);
}

export function loadConfig(): CliConfig {
  return normalizeConfig(loadConfigFile());
}

private areSourceMessageArraysEqual(
  messages1: Array<SourceMessage>,
  messages2: Array<SourceMessage>
): boolean {
  return (
    messages1.length === messages2.length &&
    messages1.every((message, index) =>
      this.areSourceMessagesEqual(message, messages2[index])
    )
  );
}

public static async getSourceFiles(
  srcPaths: Array<string>
): Promise<Set<string>> {
  const files = (
    await Promise.all(
      srcPaths.map((srcPath) =>
        SourceFileScanner.walkSourceFiles(srcPath, srcPaths)
      )
    )
  ).flat();
  return new Set(files);
}

export function compareReferences(
  refA: ExtractorMessageReference,
  refB: ExtractorMessageReference
): number {
  const pathCompare = localeCompare(refA.path, refB.path);
  if (pathCompare !== 0) return pathCompare;
  return (refA.line ?? 0) - (refB.line ?? 0);
}

function createMemoCache<Value>(
  store: Record<string, Value | undefined>
): Cache<string, Value> {
  return {
    create() {
      return {
        get(key) {
          return store[key];
        },
        set(key, value) {
          store[key] = value;
        }
      };
    }
  };
}

function findDomainFromHost<AppLocales extends Locales>(
  requestHeaders: Headers,
  domains: DomainsConfig<AppLocales>
) {
  const host = getHost(requestHeaders);

  if (host) {
    return domains.find((cur) => cur.domain === host);
  }

  return undefined;
}

from<T>(object?: Record<string, any>): T {
  const newObject: Record<string, unknown> = {}
  for (const key in object) {
    const value = object[key]
    if (isDate(value)) newObject[key] = new Date(value)
    else newObject[key] = value
  }
  return newObject as T
}

function entitiesChanged(
  prevEntities: any[] | undefined,
  newEntities: any[]
): boolean {
  if (prevEntities?.length !== newEntities?.length) return true

  for (let i = 0; i < prevEntities?.length; i++) {
    if (prevEntities[i] !== newEntities[i]) return true
  }

  return false
}

export async function createHash(message: string) {
  const data = new TextEncoder().encode(message)
  const hash = await crypto.subtle.digest("SHA-256", data)
  return Array.from(new Uint8Array(hash))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("")
    .toString()
}

export function toRequest(request: RequestInternal): Request {
  return new Request(request.url, {
    headers: request.headers,
    method: request.method,
    body:
      request.method === "POST"
        ? JSON.stringify(request.body ?? {})
        : undefined,
  })
}

