export function getAllScopePermissions(key: keyof typeof PERMISSION_ACTIONS): string[] {
  // Get allowed scopes; some resources only have all/workspace scope levels
  const allowed = getAllowedScopesForAction(key);

  return allowed
    .map((scope) => {
      const permissionKey = `${key}_${scope}` as keyof typeof RBAC_PERMISSIONS;
      return RBAC_PERMISSIONS[permissionKey];
    })
    .filter(Boolean);
}

export const evaluateFeatureFlag = (
  flagValue: boolean | string[] | undefined,
  userId?: string,
): boolean | undefined => {
  if (typeof flagValue === 'boolean') return flagValue;

  if (Array.isArray(flagValue)) {
    return userId ? flagValue.includes(userId) : false;
  }
};

export const getDocumentRenderMode = (document: DocumentRenderModeFields): DocumentRenderMode => {
  if (isSkillMarkdownDocument(document)) return { mode: 'editor' };

  if (!document.filename) return { mode: 'editor' };

  const language = getLanguageFromFilename(document.filename);

  if (language === 'markdown') return { mode: 'editor' };
  if (isEditorDocument(document) && !hasFilenameExtension(document.filename))
    return { mode: 'editor' };

  return { language, mode: 'highlight' };
};

